	cmd.Flags().String("feature", "", "Limit to one spec-id")
	cmd.Flags().String("since", "", "Optional cutoff window (today, Nd, RFC3339, or YYYY-MM-DD)")
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
