	cmd := &cobra.Command{
		Use:   "cycle-time",
		Short: "Show bead cycle time facts",
		Args:  cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			query, err := metricsQueryFromFlags(cmd)
			if err != nil {
